arguments.file_text:
#:property AllowUnsafeBlocks=true

Console.WriteLine($"nint size: {nint.Size} bytes");
Console.WriteLine($"nuint size: {nuint.Size} bytes");

// Test stackalloc Span<nint>
Span<nint> signedSpan = stackalloc nint[5];
for (int i = 0; i < signedSpan.Length; i++)
    signedSpan[i] = i * 10;

Console.Write("Span<nint>:  ");
foreach (var v in signedSpan)
    Console.Write($"{v} ");
Console.WriteLine();

// Test stackalloc Span<nuint>
Span<nuint> unsignedSpan = stackalloc nuint[5];
for (int i = 0; i < unsignedSpan.Length; i++)
    unsignedSpan[i] = (nuint)(i * 100);

Console.Write("Span<nuint>: ");
foreach (var v in unsignedSpan)
    Console.Write($"{v} ");
Console.WriteLine();

Console.WriteLine("stackalloc Span<nint> and Span<nuint> both work!");

